// Import of required libraries
import { test } from '@playwright/test';
import { expect, newSkyrampPlaywrightPage } from '@skyramp/skyramp';

const pageTimeout = 15000;

test('testUi', async ({ page }) => {
    test.setTimeout(61000);

    const errors: Error[] = [];
    page.on('pageerror', err => errors.push(err));

    // set default timeout for all locator/page actions in this test
    page.setDefaultTimeout(pageTimeout);
    // Wrap playwright page with Skyramp page
    page = newSkyrampPlaywrightPage(page);

    await page.goto("http://localhost:2368");
    await page.waitForLoadState('networkidle');
    await page.goto("http://localhost:2368/");
    await page.waitForLoadState('networkidle');
    await page.getByRole("link", { name: "Sign in" }).click();

    // Assert portal iframe loads and sign-in form renders correctly after portal bundle version bump
    const portalFrame = page.frameLocator('iframe');
    await portalFrame.getByRole('heading', { name: 'Sign in' }).waitFor({ state: 'visible', timeout: 10000 });
    await expect(portalFrame.getByRole('heading', { name: 'Sign in' })).toHaveText('Sign in');
    await expect(portalFrame.getByRole('textbox', { name: 'Email' })).toBeVisible();
    await expect(portalFrame.getByRole('button', { name: 'Continue' })).toBeVisible();

    expect(errors).toHaveLength(0);
});
